from typing import Dict


class Inventory:
    """Simple inventory tracker with reservation support.

    Attributes:
        stock (int): total items in stock
        reserved (int): items currently reserved for pending orders
    """

    def __init__(self, stock: int):
        self.stock = int(stock)
        self.reserved = 0

    def reserve(self, qty: int) -> None:
        """Reserve qty items. Raises ValueError if insufficient available stock."""
        qty = int(qty)
        if qty > self.available():
            raise ValueError("insufficient stock")
        self.reserved += qty

    def release(self, qty: int) -> None:
        """Release a previous reservation. Raises ValueError if release would go negative."""
        qty = int(qty)
        if qty > self.reserved:
            raise ValueError("release exceeds reserved quantity")
        self.reserved -= qty

    def available(self) -> int:
        """Return the number of items available for reservation."""
        return self.stock - self.reserved


class Wallet:
    """Simple wallet that can be charged."""

    def __init__(self, balance: float):
        self.balance = float(balance)

    def charge(self, amount: float) -> None:
        """Charge the wallet. Raises ValueError if insufficient funds."""
        amount = float(amount)
        if amount > self.balance:
            raise ValueError("insufficient funds")
        self.balance -= amount


def place_order(inventory: Inventory, wallet: Wallet, qty: int, price: float) -> Dict:
    """Place an order by reserving inventory then charging the wallet.

