    """Return True if the given role includes the specified action."""
    return action in get_permissions(role)


def is_valid_role(role):
    """Return True if role is a known role."""
    return role in ROLE_PERMISSIONS


def list_roles():
    """Return a sorted list of known roles."""
    return sorted(ROLE_PERMISSIONS.keys())
