    # Update the cache directly after writing to the DB; do not invalidate first (redundant).
    cache_set(key, value)


def read_record(key):
    cached = cache_get(key)
    if cached is not None:
        return cached
    val = db_read("records", key)
    if val is not None:
        cache_set(key, val)
    return val


def safe_update(key, value):
    ver = cache_get_version(key)
    db_write("records", key, value)
    cache_conditional_set(key, value, ver)


