def make_withdraw_steps(name, amount):
    """Split withdrawal into separate check and act steps.

    To avoid a race where both checks pass and both later withdraw, the ACT
    step re-checks the balance before performing the withdraw. This makes the
    effective check-and-act atomic in the simulated steps model.
